noncompliant:
// Preprocessor directives in macro arguments
#define PRINT(x) printf(#x "\n")

// Non-compliant usage
PRINT(
  #ifdef DEBUG
    "Debug mode"
  #else
    "Release mode"
  #endif
);

#define PROCESS(code) do { code } while(0)
PROCESS(
  #if FEATURE_X
    enableFeatureX();
  #endif
);

compliant:
// Resolve preprocessor directives outside macro calls
#define PRINT(x) printf(#x "\n")

#ifdef DEBUG
  #define MODE_STRING "Debug mode"
#else
  #define MODE_STRING "Release mode"
#endif

PRINT(MODE_STRING);

// Or structure the code differently
#define PROCESS(code) do { code } while(0)

#if FEATURE_X
  PROCESS(enableFeatureX(););
#else
  PROCESS(/* no-op */;);
#endif
